	import sailpoint.tools.*;
	import sailpoint.object.*;
	import sailpoint.api.*;
	import sailpoint.object.ProvisioningPlan.AccountRequest;
	import sailpoint.object.ProvisioningPlan.AttributeRequest;

	System.out.println("config****"+config);
  
	if(config.get("identities")==null){
		taskResult.addMessage(new Message(Message.Type.Error,"User must be select in taskDefinition",null));
		return "";
	}
	
	String IDEN_NWORK_ATTRIBUTE_NAME="name";
	String IDEN_EMPID_ATTRIBUTE_NAME="employeeId";
	String APPLICATION_NAME="AD-DS";
	String WORKFLOW_NAME="LCM Provisioning";
	String workflowName = "AD AHIS Account Create";
	
	String[] arr=config.get("identities").split(",");
	List identities = Arrays.asList(arr);
	taskResult.addMessage(new Message(Message.Type.Info,"identities: "+identities,null));
	if(identities!=null @and identities.size()>0){
		for(String userData:identities){
      QueryOptions qo = new QueryOptions();
      //Filter filter=Filter.ignoreCase(Filter.or(Filter.eq(IDEN_NWORK_ATTRIBUTE_NAME,userData),Filter.eq(IDEN_EMPID_ATTRIBUTE_NAME,userData)));
      //qo.addFilter(filter);
		  Identity identity=context.getObjectByName(Identity.class,userData);
		  if (identity ==null) {				
			taskResult.addMessage(new Message(Message.Type.Info,"Identity is NULL",null));
			
		  } else {
        ProvisioningPlan plan = new ProvisioningPlan(); 
				AccountRequest gsuitCreateRequest = new AccountRequest(); 
				gsuitCreateRequest.setApplication(APPLICATION_NAME); 
				gsuitCreateRequest.setOperation(AccountRequest.Operation.Create); 
				plan.add(gsuitCreateRequest);
				plan.setIdentity(identity);
				System.out.println("plan****"+plan.toXml());
        taskResult.addMessage(new Message(Message.Type.Info,"Creating Plan: "+plan.toXml(),null));
				 String identityName=identity.getName();
         taskResult.addMessage(new Message(Message.Type.Info,"Getting identityName: "+identityName,null));
        
        String caseName=workFlowName+" - "+identityName;
        taskResult.addMessage(new Message(Message.Type.Info,"Creating Case Number: "+identities+" Case Number: "+caseName,null));
				Attributes newWFArgs = new Attributes();
				newWFArgs.put("identityName",identityName);
				newWFArgs.put("plan",plan);
				newWFArgs.put("flow",WORKFLOW_NAME);
				newWFArgs.put("approvalScheme","none");
				newWFArgs.put("notificationScheme","none");
				newWFArgs.put("policyScheme","none");

				Date tmpDate = new Date(System.currentTimeMillis());
				scheduleWorkflow(WORKFLOW_NAME, caseName, tmpDate.getTime(), newWFArgs, "spadmin");  
			}
		  
		}
	}
